 15→export function JsonEditorPanel() {
 16→  const state = useStorybookState();
 17→  const storyId = state.storyId ?? '';
 18→
 19→  const [defaultJson, setDefaultJson] = useState<string>('');
 20→  const [text, setText] = useState<string>('');
 21→  const [error, setError] = useState<string | null>(null);
 22→  const [dirty, setDirty] = useState(false);
 23→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 24→
 25→  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));
 26→
 27→  useEffect(() => {
 28→    return () => {
 29→      if (debounceRef.current) clearTimeout(debounceRef.current);
 30→    };
 31→  }, []);
 32→
 33→  useEffect(() => {
 34→    const channel = getChannel();
 35→    if (!channel) return;
 36→
 37→    const onSetDefault = (json: string) => setDefaultJson(json);
 38→    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 39→    channel.emit(EVENTS.REQUEST_DEFAULT);
 40→
 41→    return () => { channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault); };
 42→  }, [storyId]);
 43→
 44→  useEffect(() => {
 45→    if (!ready || !defaultJson) return;
 46→    const initial = stored ?? defaultJson;
 47→    setText(initial);
 48→    setDirty(!!stored);
 49→    setError(null);
 50→  }, [ready, stored, defaultJson, storyId]);
 51→
 52→  const handleChange = useCallback(
 53→    (value: string) => {
 54→      setText(value);
 55→      setError(null);
 56→
 57→      if (debounceRef.current) clearTimeout(debounceRef.current);
 58→
 59→      debounceRef.current = setTimeout(() => {
 60→        try {
 61→          const parsed = JSON.parse(value);
 62→          save(value);
 63→          setDirty(true);
 64→          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
 65→        } catch (e) {
 66→          setError((e as Error).message);
 67→        }
 68→      }, 400);
 69→    },
 70→    [save],
 71→  );
 72→
 73→  const handleReset = useCallback(() => {
 74→    remove();
 75→    setText(defaultJson);
 76→    setDirty(false);
 77→    setError(null);
 78→    try {
 79→      getChannel()?.emit(EVENTS.UPDATE_JSON, JSON.parse(defaultJson));
 80→    } catch { /* noop */ }
 81→  }, [defaultJson, remove]);
 82→
 83→  const handleFormat = useCallback(() => {
 84→    try {
 85→      const parsed = JSON.parse(text);
 86→      const formatted = JSON.stringify(parsed, null, 2);
 87→      setText(formatted);
 88→      save(formatted);
 89→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
 90→      setError(null);
 91→    } catch (e) {
 92→      setError((e as Error).message);
 93→    }
 94→  }, [text, save]);
 95→
 96→  if (!storyId) {
 97→    return <div style={styles.empty}>Select a story to edit its JSON.</div>;
 98→  }
 99→
100→  return (
101→    <div style={styles.container}>
102→      <div style={styles.toolbar}>
103→        <span style={styles.label}>
104→          SDUI JSON {dirty && <span style={styles.badge}>edited</span>}
105→        </span>
106→        <div style={styles.actions}>
107→          <button style={styles.btn} onClick={handleFormat}>
108→            Format
109→          </button>
110→          <button
111→            style={{ ...styles.btn, ...styles.btnReset }}
112→            onClick={handleReset}
113→            disabled={!dirty}
114→          >
115→            Reset
116→          </button>
117→        </div>
118→      </div>
119→
120→      {error && <div style={styles.error}>JSON Error: {error}</div>}
121→
122→      <textarea
123→        style={styles.textarea}
124→        value={text}
125→        onChange={e => handleChange(e.target.value)}
126→        spellCheck={false}
127→      />
128→    </div>
129→  );
130→}
